module top_module(
    input A,
    input disable,
    input sleep,
    output reg X
);always @(A, disable, sleep) begin
    if (sleep) begin
        // If sleep is high, hold the output at the last value of A
        X <= X;
    end else if (disable) begin
        // If disable is high, pass the input signal to the output
        X <= A;
    end else begin
        // If disable is low, hold the output at the last value of A
        X <= X;
    end
end

endmodule
